    let scan_ports: &[u16] = &[
        21, 22, 23, 25, 80, 111, 135, 139, 443, 445, 993, 995, 2222, 3306, 3389, 5432, 5900,
        6379, 8080, 8443, 8888, 9090, 9200, 27017,
