        match send_raw_proto(allowed_cidr_ip, 47, &gre_payload, timeout) {
            Ok(replied) => {
                if replied {
                    return fail(format!(
                        "BREACH: GRE (proto 47) to allowed {} — response received",
                        allowed_cidr_ip
                    ));
                }
            }
            Err(_) => {}
        }
